```python
def separate_paren_groups(paren_string: str) -> List[str]:
    paren_string = paren_string.replace(" ", "")
    groups = []
    stack = []
    current_group = []

    for char in paren_string:
        if char == '(':
            if not stack:
                current_group = []
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            if stack:
                stack.pop()
                current_group.append(char)
                if not stack:
                    groups.append(''.join(current_group))

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    result = []
    stack = []
    current_group = []

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if not stack:
                current_group = []
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            if stack:
                current_group.append(char)
                stack.pop()
                if not stack:
                    result.append(''.join(current_group))

    return result
```

